If you want to avoid recalculating the positions of all elements on the screen every time you adjust the virtual window area, you can use a different approach. Instead of modifying the rendering area, you can modify the rendering transformation using a combination of the SDL_RenderSetLogicalSize() and SDL_RenderSetScale() functions.

Here’s an alternative method to create a virtual window in SDL2 C++ that can be moved and affects the rendered screen as well as the input handling:


SDL_Init(SDL_INIT_VIDEO);
SDL_Window* window = SDL_CreateWindow(“Virtual Window”, SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 800, 600, SDL_WINDOW_SHOWN);
SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

int virtualWindowWidth = 400;  // Example virtual window width
int virtualWindowHeight = 300; // Example virtual window height
int virtualWindowX = 200;      // Example virtual window X position within the main window
int virtualWindowY = 150;      // Example virtual window Y position within the main window

// Set the logical size of the virtual window
SDL_RenderSetLogicalSize(renderer, virtualWindowWidth, virtualWindowHeight);

SDL_Event event;
bool quit = false;

while (!quit) {
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            quit = true;
        }
        else if (event.type == SDL_KEYDOWN || event.type == SDL_KEYUP) {
            // Handle keyboard input
            // Adjust input coordinates for the virtual window position
            int x = event.key.x - virtualWindowX;
            int y = event.key.y - virtualWindowY;
            // Process the key event according to the adjusted coordinates
            //

// ...
        }
        else if (event.type == SDL_MOUSEBUTTONDOWN || event.type == SDL_MOUSEBUTTONUP) {
            // Handle mouse input
            // Adjust input coordinates for the virtual window position
            int x = event.button.x - virtualWindowX;
            int y = event.button.y - virtualWindowY;
            // Process the mouse event according to the adjusted coordinates
            // ...
        }
    }

    // ...

    // Set the rendering transformation to adjust for the virtual window position
    SDL_RenderSetScale(renderer, 1, 1);
    SDL_RenderSetViewport(renderer, NULL);

    // Clear the screen
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Render the virtual window content
    // ...

    // Present the rendered content
    SDL_RenderPresent(renderer);
}

SDL_DestroyRenderer(renderer);
SDL_DestroyWindow(window);
SDL_Quit();

If you're using SDL viewports and are unable to use SDL's `SDL_RenderSetLogicalSize` function, another option for drawing a virtual window is to manually calculate and adjust the rendering coordinates for all elements within the virtual window.

Here's an example of how you can achieve this:

```cpp
SDL_Init(SDL_INIT_VIDEO);
SDL_Window* window = SDL_CreateWindow("Virtual Window", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 800, 600, SDL_WINDOW_SHOWN);
SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

int virtualWindowWidth = 400;  // Example virtual window width
int virtualWindowHeight = 300; // Example virtual window height
int virtualWindowX = 200;      // Example virtual window X position within the main window
int virtualWindowY = 150;      // Example virtual window Y position within the main window

SDL_Event event;
bool quit = false;

while (!quit) {
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            quit = true;
        }
        else if (event.type == SDL_KEYDOWN || event.type == SDL_KEYUP) {
            // Handle keyboard input
            // Adjust input coordinates for the virtual window position
            int x = event.key.x - virtualWindowX;
            int y = event.key.y - virtualWindowY;
            // Process the key event according to the adjusted coordinates
        }
        else if (event.type == SDL_MOUSEBUTTONDOWN || event.type == SDL_MOUSEBUTTONUP) {
            // Handle mouse input
            // Adjust input coordinates for the virtual window position
            int x = event.button.x - virtualWindowX;
            int y = event.button.y - virtualWindowY;
            // Process the mouse event according to the adjusted coordinates
        }
    }

    // ...

    // Clear the screen
    SDL_RenderSetViewport(renderer, NULL);
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Set the rendering transformation to adjust for the virtual window position
    SDL_Rect viewport = { virtualWindowX, virtualWindowY, virtualWindowWidth, virtualWindowHeight };
    SDL_RenderSetViewport(renderer, &viewport);

    // Render the virtual window content
    // ...

    // Present the rendered content
    SDL_RenderPresent(renderer);
}

SDL_DestroyRenderer(renderer);
SDL_DestroyWindow(window);
SDL_Quit();
```

In this approach, instead of relying on `SDL_RenderSetLogicalSize`, you manually set the viewport to only render within the specified virtual window's coordinates. The rendering transformation is adjusted by setting the `SDL_Rect` viewport to the virtual window's position and dimensions. This allows you to render elements within the virtual window without affecting the main window's rendering.

To offset where the render is drawn in SDL2 C++, you can use the `SDL_RenderSetViewport` function to set a specific viewport that defines the area of the window to be rendered. By adjusting the position of the viewport, you can effectively offset the rendering.

Here's an example of how you can offset the rendering:

```cpp
SDL_Init(SDL_INIT_VIDEO);
SDL_Window* window = SDL_CreateWindow("Offset Render", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 800, 600, SDL_WINDOW_SHOWN);
SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

int xOffset = 100;  // Example offset in the X direction
int yOffset = 50;   // Example offset in the Y direction

SDL_Event event;
bool quit = false;

while (!quit) {
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            quit = true;
        }
    }

    // ...

    // Clear the screen
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Set the viewport with the desired offset
    SDL_Rect viewport = { xOffset, yOffset, 800, 600 };
    SDL_RenderSetViewport(renderer, &viewport);

    // Render the content with the adjusted viewport
    // ...

    // Present the rendered content
    SDL_RenderPresent(renderer);
}

SDL_DestroyRenderer(renderer);
SDL_DestroyWindow(window);
SDL_Quit();
```

In this example, the `xOffset` and `yOffset` variables define the desired offset in the X and Y directions, respectively. The viewport is then set using `SDL_RenderSetViewport` with the adjusted position and dimensions. The content within the adjusted viewport's coordinates will be rendered with the applied offset.

Yes, if you move the viewport, you will need to move all of the objects within the viewport so that they match up with the new viewport positions. This is because the viewport defines the visible area within the window where rendering occurs. If you offset the viewport, the objects within the viewport need to be adjusted accordingly in order to be rendered correctly in their new positions.

Here's an example of how you can adjust the positions of objects within the new viewport:

```cpp
SDL_Init(SDL_INIT_VIDEO);
SDL_Window* window = SDL_CreateWindow("Offset Render", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 800, 600, SDL_WINDOW_SHOWN);
SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

int xOffset = 100;  // Example offset in the X direction
int yOffset = 50;   // Example offset in the Y direction

// Example object positions
int object1X = 200;
int object1Y = 150;
int object2X = 400;
int object2Y = 300;

SDL_Event event;
bool quit = false;

while (!quit) {
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            quit = true;
        }
    }

    // ...

    // Clear the screen
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Set the viewport with the desired offset
    SDL_Rect viewport = { xOffset, yOffset, 800, 600 };
    SDL_RenderSetViewport(renderer, &viewport);

    // Render the content with the adjusted viewport
    // Render objects within the adjusted viewport positions
    SDL_Rect object1Rect = { object1X - xOffset, object1Y - yOffset, /* Object width */, /* Object height */ };
    SDL_Rect object2Rect = { object2X - xOffset, object2Y - yOffset, /* Object width */, /* Object height */ };
    SDL_SetRenderDrawColor(renderer, /* Object color */);
    SDL_RenderFillRect(renderer, &object1Rect);
    SDL_RenderFillRect(renderer, &object2Rect);

    // Present the rendered content
    SDL_RenderPresent(renderer);
}

SDL_DestroyRenderer(renderer);
SDL_DestroyWindow(window);
SDL_Quit();
```

In this example, the positions of objects (`object1X`, `object1Y`, `object2X`, `object2Y`) are adjusted by subtracting the offset from their original positions. This ensures that the objects are rendered correctly within the adjusted viewport. Note that you should adjust the positions of all objects that should be rendered within the viewport.
